{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires finding a sequence of sibling merges to transform one tree into another. This involves identifying which nodes in the initial tree must be merged to match the structure and values of the final tree, while respecting the rule that only siblings can be merged and the larger value is preserved.",
  "helpers": [
    {
      "label": "tree_structure_analyzer",
      "instructions": "Analyze the initial and final trees to identify the mapping between nodes. Specifically, for each node in the final tree, identify which set of nodes in the initial tree must have been merged to form it. A node in the final tree corresponds to a set of nodes in the initial tree that share the same parent and are descendants of the same ancestor in a way that satisfies the 'larger value is kept' and 'union of children' rules. Output a mapping where each final node is associated with a list of initial nodes that compose it."
    },
    {
      "label": "merge_sequence_generator",
      "instructions": "Given the mapping of initial nodes to final nodes, generate a valid sequence of merge operations. For each final node that is composed of multiple initial nodes, determine the order of merges. Since merging two siblings results in the larger value being kept, the merges must be performed such that we never accidentally merge a node that should have remained distinct. A safe strategy is to merge nodes in increasing order of their values within each sibling group to ensure the 'larger value' rule is handled predictably. Output the list of pairs (u, v) to be merged."
    }
  ],
  "synthesis_brief": "Combine the mapping from the analyzer with the sequence from the generator. The analyzer provides the 'what' (which nodes belong together) and the generator provides the 'how' (the specific order of operations). The final output should be the total count of operations followed by the pairs of node values."
}

